    @field_validator('bootdisk')
    def bootdisk_validate_regular_expression(cls, value):
        """Validates the regular expression"""
        if value is None:
            return value

        if not isinstance(value, str):
            value = str(value)

        if not re.match(r"(ide|sata|scsi|virtio)\d+", value):
            raise ValueError(r"must validate the regular expression /(ide|sata|scsi|virtio)\d+/")
        return value


















